{
    "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
    "description": "Scatterplot of US Gross vs. Worldwide Gross of movies",
    "data": {"url": "artifacts/data.csv"},
    "mark": "point",
    "encoding": {
        "x": {
            "field": "US_Gross",
            "type": "quantitative",
            "title": "US Gross"
        },
        "y": {
            "field": "Worldwide_Gross",
            "type": "quantitative",
            "title": "Worldwide Gross"
        },
        "tooltip": [
            {"field": "Title", "type": "nominal", "title": "Movie Title"},
            {"field": "US_Gross", "type": "quantitative", "title": "US Gross"},
            {"field": "Worldwide_Gross", "type": "quantitative", "title": "Worldwide Gross"}
        ]
    }
}

{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "description": "Scatterplot of US Gross vs. Worldwide Gross of movies",
  "data": {
    "url": "artifacts/data-rev1.csv"
  },
  "mark": {
    "type": "point",
    "opacity": 0.45
  },
  "encoding": {
    "x": {
      "field": "US_Gross",
      "type": "quantitative",
      "title": "US Gross",
      "scale": {
        "type": "log"
      }
    },
    "y": {
      "field": "Worldwide_Gross",
      "type": "quantitative",
      "title": "Worldwide Gross",
      "scale": {
        "type": "log"
      }
    },
    "tooltip": [
      {
        "field": "Title",
        "type": "nominal",
        "title": "Movie Title"
      },
      {
        "field": "US_Gross",
        "type": "quantitative",
        "title": "US Gross"
      },
      {
        "field": "Worldwide_Gross",
        "type": "quantitative",
        "title": "Worldwide Gross"
      }
    ]
  }
}
